mapper.select:
SELECT COUNT(CommentNo)
FROM BoardComment
WHERE BoardNo=#{BoardNo} OR ImageNo=#{ImageNo}

mapper.insert:
INSERT INTO BoardComment(
			CommentNo
			, UserId
			, CommentContent
			, CommentDate
			, CommentGroupNo
			, CommentUpperNo
			, CommentIndent
			, ImageNo
			, BoardNo)
	VALUES(
			Comment_SEQ.NEXTVAL
			, #{UserId}
			, #{CommentContent}
			, sysdate
			, #{CommentGroupNo}
			, #{CommentUpperNo}
			, #{CommentIndent}
			, #{ImageNo}
			, #{BoardNo}
	)
